INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-de09bf8b-moex-00009', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關刑法第28條共同正犯的敘述，下列何者正確？', '["共同犯意聯絡以數人之間直接聯絡為限", "甲強盜乙之財物既遂，兩天後丙協助將該贓物運往其他縣市，丙仍與甲成立強盜罪之共同正犯", "甲、乙共同謀議毆打丙，乙於行為時過於激動，突然拿起路旁的石塊朝丙的頭部砸去，丙當場 死亡。甲、乙成立殺人罪之共同正犯", "甲、乙共同唆使丙傷害丁，甲、乙應各自成立教唆傷害罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00010', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '關於不同判決宣告刑之數罪併罰，下列何者錯誤？', '["於裁判確定後，發覺未經裁判之餘罪者，僅就餘罪處斷", "得另行依刑法第51條之規定，定其應執行之刑", "如因各罪中有受赦免而僅餘一罪者，依其宣告之刑執行", "定執行刑後如發覺其他裁判確定前所犯之罪，不得再定應執行刑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00011', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '關於刑法中的刑之加重與減輕適用原則，下列何者錯誤？', '["死刑不得加重", "無期徒刑得加重為死刑", "刑有加重及減輕者，先加後減", "死刑減輕者為無期徒刑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00012', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '關於假釋制度的敘述，下列何者錯誤？', '["假釋是一種提早釋放改過遷善之受刑人出獄的制度", "初次犯罪而受有期徒刑宣告之人，有期徒刑執行逾刑期的2分之1，得許假釋", "無期徒刑假釋後滿20年，假釋未經撤銷者，未執行之刑以已執行論", "有期徒刑執行未滿6個月，亦得假釋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00013', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關刑法第87條監護處分，下列敘述何者錯誤？', '["須以行為人有再犯或有危害公共安全之虞為限", "在第19條第2項及第20條之情形，原則上於刑之執行完畢或赦免後實施處分", "若執行中認無繼續執行之必要時，法院得免其處分繼續執行", "處分期間最長不得超過5年，亦不得延長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00014', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '下列何項物品，並非屬刑法第138條所稱的「公務員職務上掌管文書物品」？', '["國家考試監試人員的彌封袋", "扣押物", "放置在公家機關的植物盆栽", "警察持有之移動式雷達測速照相機"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00015', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關刑法第135條妨害公務罪之敘述，下列何者錯誤？', '["本罪所稱之強暴脅迫，只要公務員在執行職務上受到影響即為已足，無須達到無法抗拒之程度", "本罪之成立，不以公務員執行之職務確實有受到妨害之結果為必要", "對於公務員非法執行職務行為加以反抗，不成立本罪", "於公務員依法執行職務時消極不予配合，亦成立本罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00016', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲持刀傷害A致死，聯絡同居人乙騎車到現場，知情的乙載甲前往乙租屋處藏匿。警方隨即展開 調查，甲藏匿一個月後，仍遭警察查獲。有關甲、乙之刑責，下列敘述何者正確？', '["乙成立傷害致死罪之幫助犯", "乙僅為同居人，其藏匿人犯行為不得減免其刑", "甲成立藏匿人犯罪之教唆犯", "藏匿人犯罪之所謂「犯人」，以起訴後之人為限，乙不成立藏匿人犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00017', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '刑法第190條之1規定，有關污染空氣、土壤或水體罪，下列敘述何者正確？', '["本罪之處罰，以「致生公共危險」為要件", "本罪所處罰之行為人，包含實行污染行為之自然人與法人", "本罪侵害客體包括空氣、土壤、河川或其他水體", "本罪之處罰，以故意既遂犯為限，過失犯與未遂犯之情形並不處罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00018', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '關於刑法第173條放火罪客體之敘述，下列何者錯誤？', '["現供人使用之住宅，於放火行為時，不以有人在內為必要", "現有人所在之建築物，指非供人居住生活，而屬住宅以外之建築物，如活動式檳榔攤", "有人所在之公車，屬放火罪之客體", "公寓大廈之住戶對自己居住的住宅放火，仍屬對現供人使用之住宅放火"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL)
